#include<bits/stdc++.h>
using namespace std;
struct segment_tree
{
    struct node
    {
        long long l,r,flagl,flagr,ans;
        long long lson,rson;
        long long tag;
        node():tag(0){}
    }a[600010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(node &x,node l,node r)
    {
        x.flagl=l.flagl;
        x.flagr=r.flagr;
        x.ans=l.ans+r.ans-(int)(l.flagr&&r.flagl);
    }
    void pushup(long long x)
    {
        pushup(a[x],a[a[x].lson],a[a[x].rson]);
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].flagl=a[x].flagr=a[x].ans=0;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,long long z)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].flagl=a[x].flagr=a[x].ans=z;
            return;
        }
        update(a[x].lson,p,z);
        update(a[x].rson,p,z);
        pushup(x);
    }
    node getans(long long x,long long l,long long r)
    {
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x];
        }
        int mid=(a[x].l+a[x].r)>>1;
        if(l<=mid&&mid+1<=r)
        {
            node now;
            now.flagl=now.flagr=now.ans=0;
            pushup(now,getans(a[x].lson,l,r),getans(a[x].rson,l,r));
            return now;
        }
        else if(l<=mid)
        {
            return getans(a[x].lson,l,r);
        }
        else
        {
            return getans(a[x].rson,l,r);
        }
    }
}t;
long long n,q;
struct query
{
    long long l,r,x,id;
    bool operator<(const query&b)const
    {
        return x>b.x;
    }
}b[200010];
long long ans[200010];
struct node
{
    long long val,id;
    bool operator<(const node&b)const
    {
        return val>b.val;
    }
}a[200010];
int main()
{
    scanf("%lld%lld",&n,&q);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i].val);
        a[i].id=i;
    }
    for(long long i=1;i<=q;i++)
    {
        scanf("%lld%lld%lld",&b[i].l,&b[i].r,&b[i].x);
        b[i].id=i;
    }
    sort(a+1,a+1+n);
    sort(b+1,b+1+q);
    long long j=1;
    t.init(1,n);
    for(long long i=1;i<=q;i++)
    {
        while(j<=n&&a[j].val>b[i].x)
        {
            t.update(1,a[j].id,1);
            j++;
        }
        ans[b[i].id]=t.getans(1,b[i].l,b[i].r).ans;
    }
    for(long long i=1;i<=q;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
